class SubscriptionTierEnum(graphene.Enum):
    FREE = "free"
    BASIC = "basic"
    PRO = "pro"
    ENTERPRISE = "enterprise"


class RoleEnum(graphene.Enum):
    USER = "user"
    MODERATOR = "moderator"
    ADMIN = "admin"


class UserType(ObjectType):
    id = String(required=True)
    username = String(required=True)
    email = String(required=True)
    bio = String()
    role = String(required=True)
    is_admin = Boolean(required=True)
    credits = Int(required=True)
    subscription_tier = String(required=True)


class UpdateUserProfile(Mutation):
    class Arguments:
        user_id = String(description="Target user ID to update. If not provided, updates the authenticated user.")
        username = String(description="New username")
        email = String(description="New email address")
        bio = String(description="New bio text")
        role = RoleEnum(description="New role (admin only)")
        is_admin = Boolean(description="Admin status (admin only)")
        credits = Int(description="Credit balance (admin only)")
        subscription_tier = SubscriptionTierEnum(description="Subscription tier (admin only)")

    user = Field(UserType)
    success = Boolean(required=True)
    message = String(required=True)

    @staticmethod
    def mutate(root, info, user_id=None, **kwargs):
        # Get authenticated user from context
        authenticated_user = info.context.get("user") if isinstance(info.context, dict) else None

        if not authenticated_user:
            return UpdateUserProfile(user=None, success=False, message="Authentication required.")

        auth_user_id = authenticated_user.get("id")
        auth_user_data = USERS_DB.get(auth_user_id)

        if not auth_user_data:
            return UpdateUserProfile(user=None, success=False, message="Authenticated user not found in database.")

        is_admin = auth_user_data.get("is_admin", False)

        # Determine target user
        target_user_id = user_id if user_id else auth_user_id

        if target_user_id not in USERS_DB:
            return UpdateUserProfile(user=None, success=False, message=f"User with ID '{target_user_id}' not found.")

        is_self_update = target_user_id == auth_user_id

        # Non-admins can only update their own profile
        if not is_self_update and not is_admin:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="Permission denied. You can only update your own profile.",
            )

        # Define which fields are privileged (admin-only)
        admin_only_fields = {"role", "is_admin", "credits", "subscription_tier"}
        self_editable_fields = {"username", "email", "bio"}

        # Convert enum values to their string values
        resolved_kwargs = {}
        for key, value in kwargs.items():
            if value is not None:
                if hasattr(value, "value"):
                    resolved_kwargs[key] = value.value
                else:
                    resolved_kwargs[key] = value

        # Check if non-admin is trying to set privileged fields
        if not is_admin:
            attempted_admin_fields = set(resolved_kwargs.keys()) & admin_only_fields
            if attempted_admin_fields:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Permission denied. Only admins can modify: {', '.join(sorted(attempted_admin_fields))}.",
                )

        # Validate provided fields
        if "username" in resolved_kwargs:
            username = resolved_kwargs["username"]
            if not username or len(username.strip()) < 3:
                return UpdateUserProfile(
                    user=None, success=False, message="Username must be at least 3 characters long."
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != target_user_id and udata["username"] == username.strip():
                    return UpdateUserProfile(
                        user=None, success=False, message=f"Username '{username}' is already taken."
                    )
            resolved_kwargs["username"] = username.strip()

        if "email" in resolved_kwargs:
            email = resolved_kwargs["email"]
            if not email or "@" not in email or "." not in email.split("@")[-1]:
                return UpdateUserProfile(
                    user=None, success=False, message="A valid email address is required."
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != target_user_id and udata["email"] == email.strip().lower():
                    return UpdateUserProfile(
                        user=None, success=False, message=f"Email '{email}' is already in use."
                    )
            resolved_kwargs["email"] = email.strip().lower()

        if "bio" in resolved_kwargs:
            bio = resolved_kwargs["bio"]
            if bio and len(bio) > 500:
                return UpdateUserProfile(
                    user=None, success=False, message="Bio must be 500 characters or fewer."
                )

        if "credits" in resolved_kwargs:
            credits_val = resolved_kwargs["credits"]
            if credits_val < 0:
                return UpdateUserProfile(
                    user=None, success=False, message="Credits cannot be negative."
                )

        if "role" in resolved_kwargs:
            valid_roles = {"user", "moderator", "admin"}
            if resolved_kwargs["role"] not in valid_roles:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid role. Must be one of: {', '.join(sorted(valid_roles))}.",
                )

        if "subscription_tier" in resolved_kwargs:
            valid_tiers = {"free", "basic", "pro", "enterprise"}
            if resolved_kwargs["subscription_tier"] not in valid_tiers:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid subscription tier. Must be one of: {', '.join(sorted(valid_tiers))}.",
                )

        if not resolved_kwargs:
            return UpdateUserProfile(
                user=None, success=False, message="No fields provided to update."
            )

        # Apply updates
        target_user = USERS_DB[target_user_id]
        updated_fields = []
        for field_name, field_value in resolved_kwargs.items():
            if field_name in target_user and target_user[field_name] != field_value:
                target_user[field_name] = field_value
                updated_fields.append(field_name)
            elif field_name in target_user and target_user[field_name] == field_value:
                pass  # No change needed
            else:
                target_user[field_name] = field_value
                updated_fields.append(field_name)

        user_obj = UserType(
            id=target_user["id"],
            username=target_user["username"],
            email=target_user["email"],
            bio=target_user["bio"],
            role=target_user["role"],
            is_admin=target_user["is_admin"],
            credits=target_user["credits"],
            subscription_tier=target_user["subscription_tier"],
        )

        if updated_fields:
            message = f"Profile updated successfully. Changed fields: {', '.join(sorted(updated_fields))}."
        else:
            message = "No changes were made (values are the same as current)."

        return UpdateUserProfile(user=user_obj, success=True, message=message)


class Query(ObjectType):
    me = Field(UserType, description="Get the currently authenticated user's profile")
    user = Field(UserType, user_id=String(required=True), description="Get a user by ID (admin only)")
    all_users = graphene.List(UserType, description="List all users (admin only)")

    @staticmethod
    def resolve_me(root, info):
        authenticated_user = info.context.get("user") if isinstance(info.context, dict) else None
        if not authenticated_user:
            return None
        user_data = USERS_DB.get(authenticated_user.get("id"))
        if not user_data:
            return None
        return UserType(**user_data)

    @staticmethod
    def resolve_user(root, info, user_id):
        authenticated_user = info.context.get("user") if isinstance(info.context, dict) else None
        if not authenticated_user:
            return None
        auth_user_data = USERS_DB.get(authenticated_user.get("id"))
        if not auth_user_data or not auth_user_data.get("is_admin"):
            return None
        user_data = USERS_DB.get(user_id)
        if not user_data:
            return None
        return UserType(**user_data)

    @staticmethod
    def resolve_all_users(root, info):
        authenticated_user = info.context.get("user") if isinstance(info.context, dict) else None
        if not authenticated_user:
            return []
        auth_user_data = USERS_DB.get(authenticated_user.get("id"))
        if not auth_user_data or not auth_user_data.get("is_admin"):
            return []
        return [UserType(**user_data) for user_data in USERS_DB.values()]


class Mutations(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=Mutations)


def execute_query(query_string, context=None, variables=None):
    """Helper function to execute a GraphQL query with context."""
    result = schema.execute(
        query_string,
        context=context or {},
        variables=variables,
    )
    response = {}
    if result.data:
        response["data"] = result.data
    if result.errors:
        response["errors"] = [str(e) for e in result.errors]
    return response


